// // This module checks if either A1 and A2 are both low, or if B1 and C1 are both low. If so, X is high; otherwise, X is low.
module my_module (
    input A1,
    input A2,
    input B1,
    input C1,
    output reg X
);

    always @(*) begin
        if ((A1 & A2) || (B1 & C1))
            X = 1;
        else
            X = 0;
    end

endmodule
